INSERT INTO bible_book_intros (book_abbr, lang, author, time_of_writing, place_of_writing, time_period_covered, subject, recipient) VALUES
('Gen','sc','摩西，五卷律法书的著者（申三一9，24，路二四27，44，约一45，五46，徒二八23，林后三15）','约于主前一四九○年，与出埃及记同时（见该书书介）','埃及东边的旷野','从起初的创造（一1）到主前约一六三五年，约瑟去世之时（五十26）','神创造，撒但败坏，人堕落，耶和华应许拯救',''),
('Gen','zh','摩西，五卷律法書的著者（申三一9，24，路二四27，44，約一45，五46，徒二八23，林後三15）','約於主前一四九○年，與出埃及記同時（見該書書介）','埃及東邊的曠野','從起初的創造（一1）到主前約一六三五年，約瑟去世之時（五十26）','神創造，撒但敗壞，人墮落，耶和華應許拯救',''),
('Exo','sc','摩西，（可十二26与路二十37，引用出三6；可七10，引用出二十12，）五卷律法书的著者（申三一9，24，路二四27，44，约一45，五46，徒二八23，林后三15）','约于主前一四九○年，（参王上六1，）即以色列人出埃及后第二年，帐幕立起之后（四十17）','旷野及西乃山（十九1～2，三四27～29）','从主前约一七○六年雅各到埃及（一1）起，到主前一四九○年，即以色列人出埃及后一年（四十17','基督是神子民的救赎、拯救和供应，也是他们敬拜并事奉神的凭借，使他们在祂里面与神建造在一起，而得与神相见，彼此交通，互为居所',''),
('Exo','zh','摩西，（可十二26與路二十37，引用出三6；可七10，引用出二十12，）五卷律法書的著者（申三一9，24，路二四27，44，約一45，五46，徒二八23，林後三15）','約於主前一四九○年，（參王上六1，）即以色列人出埃及後第二年，帳幕立起之後（四十17）','曠野及西乃山（十九1～2，三四27～29）','從主前約一七○六年雅各到埃及（一1）起，到主前一四九○年，即以色列人出埃及後一年（四十17','基督是神子民的救贖、拯救和供應，也是他們敬拜並事奉神的憑藉，使他們在祂裡面與神建造在一起，而得與神相見，彼此交通，互為居所',''),
('Lev','sc','摩西，（太八4，指向利十四10～32；罗十5，引用利十八5，）五卷律法书的著者（申三一9，24，路二四27，44，约一45，五46，徒二八23，林后三15）','约于主前一四九○年，（参王上六1，）即以色列人出埃及后第二年，帐幕立起之后（一1）','旷野，西乃山附近（一1，出十九2）','一个月，从以色列人出埃及后第二年正月初一日帐幕立起时（出四十17），到同年（主前一四九○年）二月初一日（民一1）','基督是蒙神救赎的人在交通、事奉和生活上的一切',''),
('Lev','zh','摩西，（太八4，指向利十四10～32；羅十5，引用利十八5，）五卷律法書的著者（申三一9，24，路二四27，44，約一45，五46，徒二八23，林後三15）','約於主前一四九○年，（參王上六1，）即以色列人出埃及後第二年，帳幕立起之後（一1）','曠野，西乃山附近（一1，出十九2）','一個月，從以色列人出埃及後第二年正月初一日帳幕立起時（出四十17），到同年（主前一四九○年）二月初一日（民一1）','基督是蒙神救贖的人在交通、事奉和生活上的一切',''),
('Num','sc','摩西，（三三2；拉六18指向民三6～7，）五卷律法书的著者（申三一9，24，路二四27，44，约一45，五46，徒二八23，林后三15）','约于主前一四五二年，以色列人在旷野飘流四十年结束以前（三二13）','摩押平原与耶利哥相对的约但河边（三六13）','主前一四九○至一四五二年，为时近三十九年，从以色列人出埃及后第二年二月（一1），到第四十年十月（申一3）','基督是神子民的生活意义、见证、中心，以及他们行程和争战的领导、道路与目标',''),
('Num','zh','摩西，（三三2；拉六18指向民三6～7，）五卷律法書的著者（申三一9，24，路二四27，44，約一45，五46，徒二八23，林後三15）','約於主前一四五二年，以色列人在曠野飄流四十年結束以前（三二13）','摩押平原與耶利哥相對的約但河邊（三六13）','主前一四九○至一四五二年，為時近三十九年，從以色列人出埃及後第二年二月（一1），到第四十年十月（申一3）','基督是神子民的生活意義、見證、中心，以及他們行程和爭戰的領導、道路與目標',''),
('Deut','sc','摩西，（罗十19引用申三二21；尼十三1指向申二三3；路二十28指向申二五5，）五卷律法书的著者（三一9，24，路二四27，44，约一45，五46，徒二八23，林后三15）','约于主前一四五二年，以色列人在旷野飘流四十年结束以前（民三二13）','摩押平原（三四1）','主前一四五二年，以色列人出埃及后第四十年，末了两个月（一3，三四8）','基督是神子民的指导者和领导者，使他们能进入属天的领域，并有分于祂的丰富',''),
('Deut','zh','摩西，（羅十19引用申三二21；尼十三1指向申二三3；路二十28指向申二五5，）五卷律法書的著者（三一9，24，路二四27，44，約一45，五46，徒二八23，林後三15）','約於主前一四五二年，以色列人在曠野飄流四十年結束以前（民三二13）','摩押平原（三四1）','主前一四五二年，以色列人出埃及後第四十年，末了兩個月（一3，三四8）','基督是神子民的指導者和領導者，使他們能進入屬天的領域，並有分於祂的豐富',''),
('Josh','sc','约书亚（二四26）','主前一四五二至一四二六年（见后文）','','主前一四五二至一四二六年，为时约二十七年，从以色列人出埃及后第四十一年正月（四19），到约书亚离世（二四29）','以色列人占有并得着美地为业，以完成神的经纶',''),
('Josh','zh','約書亞（二四26）','主前一四五二至一四二六年（見後文）','','主前一四五二至一四二六年，為時約二十七年，從以色列人出埃及後第四十一年正月（四19），到約書亞離世（二四29）','以色列人佔有並得著美地為業，以完成神的經綸',''),
('Judg','sc','也许是撒母耳','主前第十一世纪','','主前约一四二五年至主前一一二○年，为时约三百零五年，从约书亚死后（一1）到参孙死时（十六30～31，参徒十三19～20）','以色列离弃神，遭仇敌击败，渐渐腐败',''),
('Judg','zh','也許是撒母耳','主前第十一世紀','','主前約一四二五年至主前一一二○年，為時約三百零五年，從約書亞死後（一1）到參孫死時（十六30～31，參徒十三19～20）','以色列離棄神，遭仇敵擊敗，漸漸腐敗',''),
('Ruth','sc','按本书内容看，著者应为撒母耳','主前第十一世纪，士师秉政之后，列王掌权之时（参四22）','','主前约一三二二年至主前约一三一二年，为时约十一年（一4，四13）','一幅完整的表号，说到外邦的罪人，借着基督的救赎而与基督联结，与神的选民以色列同被带进神圣的产业',''),
('Ruth','zh','按本書內容看，著者應為撒母耳','主前第十一世紀，士師秉政之後，列王掌權之時（參四22）','','主前約一三二二年至主前約一三一二年，為時約十一年（一4，四13）','一幅完整的表號，說到外邦的罪人，藉著基督的救贖而與基督聯結，與神的選民以色列同被帶進神聖的產業',''),
('1Sam','sc','撒母耳记上、下在希伯来文圣经中原为一卷','主前第十一世纪','以法莲和犹大','约于主前一一七一～一○一七年，共约一百五十五年','享受神所赐美地之路的例证',''),
('1Sam','zh','撒母耳記上、下在希伯來文聖經中原為一卷','主前第十一世紀','以法蓮和猶大','約於主前一一七一～一○一七年，共約一百五十五年','享受神所賜美地之路的例證',''),
('2Sam','sc','撒母耳记上、下在希伯来文圣经中原为一卷','主前第十一世纪','以法莲和犹大','约于主前一一七一～一○一七年，共约一百五十五年','享受神所赐美地之路的例证',''),
('2Sam','zh','撒母耳記上、下在希伯來文聖經中原為一卷','主前第十一世紀','以法蓮和猶大','約於主前一一七一～一○一七年，共約一百五十五年','享受神所賜美地之路的例證',''),
('1Kgs','sc','列王纪上、下在希伯来文圣经中原为一卷','以色列被掳到巴比伦期间，主前五六一年之后（王下二五27）','也许在耶路撒冷','两卷书共涵盖四百五十五年：列王纪上涵盖一百一十九年，从主前一○一五年至主前八九七年，即从大卫离世（王上二10），到以色列王亚哈的儿子亚哈谢作王的时候；（王上二二51；）列王纪下涵盖三百三十六年，从主前八九六年至主前五六一年，即从以色列王亚哈的儿子约兰作王，（王下三1～3，）到被掳之时，以未米罗达在巴比伦作王期间（王下二五27）','神在祂的经纶中，在行政上对付地上神圣君王职分因列王所受的破坏与毁坏，以及神公正对付的悲惨结果',''),
('1Kgs','zh','列王紀上、下在希伯來文聖經中原為一卷','以色列被擄到巴比倫期間，主前五六一年之後（王下二五27）','也許在耶路撒冷','兩卷書共涵蓋四百五十五年：列王紀上涵蓋一百一十九年，從主前一○一五年至主前八九七年，即從大衛離世（王上二10），到以色列王亞哈的兒子亞哈謝作王的時候；（王上二二51；）列王紀下涵蓋三百三十六年，從主前八九六年至主前五六一年，即從以色列王亞哈的兒子約蘭作王，（王下三1～3，）到被擄之時，以未米羅達在巴比倫作王期間（王下二五27）','神在祂的經綸中，在行政上對付地上神聖君王職分因列王所受的破壞與毀壞，以及神公正對付的悲慘結果',''),
('2Kgs','sc','列王纪上、下在希伯来文圣经中原为一卷','以色列被掳到巴比伦期间，主前五六一年之后（王下二五27）','也许在耶路撒冷','两卷书共涵盖四百五十五年：列王纪上涵盖一百一十九年，从主前一○一五年至主前八九七年，即从大卫离世（王上二10），到以色列王亚哈的儿子亚哈谢作王的时候；（王上二二51；）列王纪下涵盖三百三十六年，从主前八九六年至主前五六一年，即从以色列王亚哈的儿子约兰作王，（王下三1～3，）到被掳之时，以未米罗达在巴比伦作王期间（王下二五27）','神在祂的经纶中，在行政上对付地上神圣君王职分因列王所受的破坏与毁坏，以及神公正对付的悲惨结果',''),
('2Kgs','zh','列王紀上、下在希伯來文聖經中原為一卷','以色列被擄到巴比倫期間，主前五六一年之後（王下二五27）','也許在耶路撒冷','兩卷書共涵蓋四百五十五年：列王紀上涵蓋一百一十九年，從主前一○一五年至主前八九七年，即從大衛離世（王上二10），到以色列王亞哈的兒子亞哈謝作王的時候；（王上二二51；）列王紀下涵蓋三百三十六年，從主前八九六年至主前五六一年，即從以色列王亞哈的兒子約蘭作王，（王下三1～3，）到被擄之時，以未米羅達在巴比倫作王期間（王下二五27）','神在祂的經綸中，在行政上對付地上神聖君王職分因列王所受的破壞與毀壞，以及神公正對付的悲慘結果',''),
('1Chr','sc','历代志上、下在希伯来文圣经中原为一卷，也许是以斯拉所写（比较代下三六22～23与拉一1～3上）','也许在主前四五八年之后，波斯王亚达薛西在位期间（拉七1），以斯拉从巴比伦回到耶路撒冷的时候（拉八31～32）','也许在耶路撒冷','两卷书共涵盖五百二十年：历代志上涵盖约四十一年（不包括一～九章先祖的家谱），从主前一○五六年至主前一○一五年，即从扫罗离世（十）到大卫离世；（代上二九28；）历代志下涵盖约四百七十九年，从主前一○一五年至主前五三六年，即从所罗门作王（代下一1）到波斯王古列元年（代下三六22）','神在人历史中行动的全部纪事，从亚当经过撒母耳到以色列被掳归回，连同神对付犹大诸王一些重要细节的陈述',''),
('1Chr','zh','歷代志上、下在希伯來文聖經中原為一卷，也許是以斯拉所寫（比較代下三六22～23與拉一1～3上）','也許在主前四五八年之後，波斯王亞達薛西在位期間（拉七1），以斯拉從巴比倫回到耶路撒冷的時候（拉八31～32）','也許在耶路撒冷','兩卷書共涵蓋五百二十年：歷代志上涵蓋約四十一年（不包括一～九章先祖的家譜），從主前一○五六年至主前一○一五年，即從掃羅離世（十）到大衛離世；（代上二九28；）歷代志下涵蓋約四百七十九年，從主前一○一五年至主前五三六年，即從所羅門作王（代下一1）到波斯王古列元年（代下三六22）','神在人歷史中行動的全部紀事，從亞當經過撒母耳到以色列被擄歸回，連同神對付猶大諸王一些重要細節的陳述',''),
('2Chr','sc','历代志上、下在希伯来文圣经中原为一卷，也许是以斯拉所写（比较代下三六22～23与拉一1～3上）','也许在主前四五八年之后，波斯王亚达薛西在位期间（拉七1），以斯拉从巴比伦回到耶路撒冷的时候（拉八31～32）','也许在耶路撒冷','两卷书共涵盖五百二十年：历代志上涵盖约四十一年（不包括一～九章先祖的家谱），从主前一○五六年至主前一○一五年，即从扫罗离世（十）到大卫离世；（代上二九28；）历代志下涵盖约四百七十九年，从主前一○一五年至主前五三六年，即从所罗门作王（代下一1）到波斯王古列元年（代下三六22）','神在人历史中行动的全部纪事，从亚当经过撒母耳到以色列被掳归回，连同神对付犹大诸王一些重要细节的陈述',''),
('2Chr','zh','歷代志上、下在希伯來文聖經中原為一卷，也許是以斯拉所寫（比較代下三六22～23與拉一1～3上）','也許在主前四五八年之後，波斯王亞達薛西在位期間（拉七1），以斯拉從巴比倫回到耶路撒冷的時候（拉八31～32）','也許在耶路撒冷','兩卷書共涵蓋五百二十年：歷代志上涵蓋約四十一年（不包括一～九章先祖的家譜），從主前一○五六年至主前一○一五年，即從掃羅離世（十）到大衛離世；（代上二九28；）歷代志下涵蓋約四百七十九年，從主前一○一五年至主前五三六年，即從所羅門作王（代下一1）到波斯王古列元年（代下三六22）','神在人歷史中行動的全部紀事，從亞當經過撒母耳到以色列被擄歸回，連同神對付猶大諸王一些重要細節的陳述',''),
('Ezra','sc','以斯拉，为亚伦的子孙（七1～5），精通摩西律法的祭司并经学家（七6，11～12）','主前四五七年以后','耶路撒冷','本书涵盖时段约八十年，从主前五三六年到主前四五七年；即波斯王古列元年（一1），至波斯王亚达薛西第七年之后的正月初一日（十17，七7）','以色列人从被掳中归回，重建神的殿，开始神选民中间照着神的经纶，为着神在地上见证的恢复',''),
('Ezra','zh','以斯拉，為亞倫的子孫（七1～5），精通摩西律法的祭司並經學家（七6，11～12）','主前四五七年以後','耶路撒冷','本書涵蓋時段約八十年，從主前五三六年到主前四五七年；即波斯王古列元年（一1），至波斯王亞達薛西第七年之後的正月初一日（十17，七7）','以色列人從被擄中歸回，重建神的殿，開始神選民中間照著神的經綸，為著神在地上見證的恢復',''),
('Neh','sc','尼希米，为波斯和巴比伦王亚达薛西的司酒（一11）','主前四三三年以后','耶路撒冷','本书涵盖时段至少十二年，从主前四四五年到主前四三三年；即波斯和巴比伦王亚达薛西二十年（一1），至亚达薛西三十二年之后某时（十三6～7）','重建耶路撒冷的城墙，继续神选民中间祂见证的恢复，以完成祂的经纶',''),
('Neh','zh','尼希米，為波斯和巴比倫王亞達薛西的司酒（一11）','主前四三三年以後','耶路撒冷','本書涵蓋時段至少十二年，從主前四四五年到主前四三三年；即波斯和巴比倫王亞達薛西二十年（一1），至亞達薛西三十二年之後某時（十三6～7）','重建耶路撒冷的城牆，繼續神選民中間祂見證的恢復，以完成祂的經綸',''),
('Esth','sc','也许是末底改（九20，23），以斯帖的堂兄并抚养者（二5，7）','约于主前四七四年，亚哈随鲁王十二年十二月（九20，18，三7）','波斯帝国书珊京城（一2）','本书涵盖时段至少十年，从主前四八四年到主前四七四年；即波斯王亚哈随鲁第三年（一3），至亚哈随鲁十二年十二月十五日之后某时（九18，三7）','拣选以色列人作选民的这位神，在他们被掳到外邦列国中的期间，对他们成了隐藏的神，借着在隐密中行事，秘密地照顾他们，并公开地拯救他们',''),
('Esth','zh','也許是末底改（九20，23），以斯帖的堂兄並撫養者（二5，7）','約於主前四七四年，亞哈隨魯王十二年十二月（九20，18，三7）','波斯帝國書珊京城（一2）','本書涵蓋時段至少十年，從主前四八四年到主前四七四年；即波斯王亞哈隨魯第三年（一3），至亞哈隨魯十二年十二月十五日之後某時（九18，三7）','揀選以色列人作選民的這位神，在他們被擄到外邦列國中的期間，對他們成了隱藏的神，藉著在隱密中行事，秘密地照顧他們，並公開地拯救他們',''),
('Job','sc','约伯','按照约伯游牧的生活方式（一3），以及他为儿女献燔祭的方式，本书似乎写于亚伯拉罕、以撒、雅各的时期（一5，创二二13，三一54），约在主前二千年，即摩西写五经以前五百年','乌斯地（一1），此乃与以东有关联之地区，（哀四21，）位于亚拉伯旷野西边','本书涵盖时段无法准确断定；然而，约伯受试炼后又活了一百四十年（四二16），因此本书涵盖将近二百年，在主前二千年左右','神对付祂圣民的目的',''),
('Job','zh','約伯','按照約伯游牧的生活方式（一3），以及他為兒女獻燔祭的方式，本書似乎寫於亞伯拉罕、以撒、雅各的時期（一5，創二二13，三一54），約在主前二千年，即摩西寫五經以前五百年','烏斯地（一1），此乃與以東有關聯之地區，（哀四21，）位於亞拉伯曠野西邊','本書涵蓋時段無法準確斷定；然而，約伯受試煉後又活了一百四十年（四二16），因此本書涵蓋將近二百年，在主前二千年左右','神對付祂聖民的目的',''),
('Ps','sc','大卫作诗七十三篇，（三～九，十一～三二，三四～四一，五一～六五，六八～七十，八六，一○一，一○三，一○八～一一○，一二二，一二四，一三一，一三三，一三八～一四五，）可拉子孙十二篇，（四二～四九，八四～八五，八七～八八，）亚萨十二篇，（五十，七三～八三，）所罗门二篇，（七二，一二七，）以探一篇，（八九，）摩西一篇（九十）','始于主前第十一世纪（第九十篇除外，该诗由摩西写于主前第十五世纪）','主要在耶路撒冷','','寻求并接触神的敬虔之人，借着赞美、祷告、并欢腾的歌唱，所表达的情绪、感觉、感想和经历',''),
('Ps','zh','大衛作詩七十三篇，（三～九，十一～三二，三四～四一，五一～六五，六八～七十，八六，一○一，一○三，一○八～一一○，一二二，一二四，一三一，一三三，一三八～一四五，）可拉子孫十二篇，（四二～四九，八四～八五，八七～八八，）亞薩十二篇，（五十，七三～八三，）所羅門二篇，（七二，一二七，）以探一篇，（八九，）摩西一篇（九十）','始於主前第十一世紀（第九十篇除外，該詩由摩西寫於主前第十五世紀）','主要在耶路撒冷','','尋求並接觸神的敬虔之人，藉著讚美、禱告、並歡騰的歌唱，所表達的情緒、感覺、感想和經歷',''),
('Prov','sc','主要的著者及汇集者为所罗门（一1，十1，二五1，参王上四32，传十二9）和希西家，（二五1，）后者在二五至二九章加上一些先祖的箴言','主前约一千年（所罗门的部分，一至二四章）以及主前约七百年（希西家的部分，二五至二九章','也许在耶路撒冷','','智慧的话，教导人如何行事为人，并在为人生活中建立他们的性格',''),
('Prov','zh','主要的著者及彙集者為所羅門（一1，十1，二五1，參王上四32，傳十二9）和希西家，（二五1，）後者在二五至二九章加上一些先祖的箴言','主前約一千年（所羅門的部分，一至二四章）以及主前約七百年（希西家的部分，二五至二九章','也許在耶路撒冷','','智慧的話，教導人如何行事為人，並在為人生活中建立他們的性格',''),
('Eccl','sc','所罗门（一1，12，十二9，参王上四32）','约于主前九七七年，所罗门堕落之后（王上十一1～8）','耶路撒冷（一1，12）','','所罗门的教训，给人看见败坏世界里的人生，都是虚空，都是捕风',''),
('Eccl','zh','所羅門（一1，12，十二9，參王上四32）','約於主前九七七年，所羅門墮落之後（王上十一1～8）','耶路撒冷（一1，12）','','所羅門的教訓，給人看見敗壞世界裡的人生，都是虛空，都是捕風',''),
('Song','sc','所罗门（一1）','主前一千年左右','耶路撒冷','','一个绝佳婚姻里爱的历史，启示出个别信徒与基督爱的交通中进展的经历',''),
('Song','zh','所羅門（一1）','主前一千年左右','耶路撒冷','','一個絕佳婚姻裡愛的歷史，啟示出個別信徒與基督愛的交通中進展的經歷',''),
('Isa','sc','以赛亚（一1，太三3，约十二38～41，罗十五12）','主前第八世纪末期及主前第七世纪初期','耶路撒冷','约六十四年，从主前约七百六十年，即乌西雅（亚撒利雅）王去世前几年，到主前约六百九十六年，即希西家去世后几年（六1，一1）','耶和华借着成为肉体、钉死十架、复活、升天、并再来的基督所施的救恩',''),
('Isa','zh','以賽亞（一1，太三3，約十二38～41，羅十五12）','主前第八世紀末期及主前第七世紀初期','耶路撒冷','約六十四年，從主前約七百六十年，即烏西雅（亞撒利雅）王去世前幾年，到主前約六百九十六年，即希西家去世後幾年（六1，一1）','耶和華藉著成為肉體、釘死十架、復活、昇天、並再來的基督所施的救恩',''),
('Jer','sc','耶利米（一1）','主前第七世纪末期及第六世纪初期','耶路撒冷与埃及','本书涵盖时段至少四十一年，从主前六二九年，即约西亚在位第十三年（一2），到主前五八八年后某时，即犹大总督基大利被杀，（四一2，）以及耶利米被迁徙至埃及（四三6～8）之后','基督在神对付以色列与列国时，成为耶和华对神选民的义，作他们的中心和圆周',''),
('Jer','zh','耶利米（一1）','主前第七世紀末期及第六世紀初期','耶路撒冷與埃及','本書涵蓋時段至少四十一年，從主前六二九年，即約西亞在位第十三年（一2），到主前五八八年後某時，即猶大總督基大利被殺，（四一2，）以及耶利米被遷徙至埃及（四三6～8）之後','基督在神對付以色列與列國時，成為耶和華對神選民的義，作他們的中心和圓周',''),
('Lam','sc','耶利米（根据七十士希腊文译本一1；亦参代下三五25）','耶路撒冷于主前五八八年被毁之后不久','耶路撒冷','','耶利米对神的圣城和圣民之忧伤与爱的发表',''),
('Lam','zh','耶利米（根據七十士希臘文譯本一1；亦參代下三五25）','耶路撒冷於主前五八八年被毀之後不久','耶路撒冷','','耶利米對神的聖城和聖民之憂傷與愛的發表',''),
('Ezek','sc','以西结（ 一3）','主前第六世纪','迦巴鲁河边，离巴比伦城不远的提勒亚毕村庄（一1，三15）','为时二十二年，从主前五九五年至主前五七三年，即约雅斤被掳第五年（一2）至第二十七年（二九17）','神在荣耀里向人显现，审判自己的百姓和列国，并恢复祂的选民，为着建造一个居所，作相互的住处，并作祂自己完全的彰显',''),
('Ezek','zh','以西結（ 一3）','主前第六世紀','迦巴魯河邊，離巴比倫城不遠的提勒亞畢村莊（一1，三15）','為時二十二年，從主前五九五年至主前五七三年，即約雅斤被擄第五年（一2）至第二十七年（二九17）','神在榮耀裡向人顯現，審判自己的百姓和列國，並恢復祂的選民，為著建造一個居所，作相互的住處，並作祂自己完全的彰顯',''),
('Dan','sc','但以理','主前第六世纪','巴比伦','为时七十二年，从主前六○六年，即约雅敬在位第三年（一1），到主前五三四年，即古列在位第三年（十1）','神截定给以色列的定命，就是七十个七的内容',''),
('Dan','zh','但以理','主前第六世紀','巴比倫','為時七十二年，從主前六○六年，即約雅敬在位第三年（一1），到主前五三四年，即古列在位第三年（十1）','神截定給以色列的定命，就是七十個七的內容',''),
('Hos','sc','何西阿（一1）','','','','耶和华是邪淫背道之以色列的救恩，接纳她回来并复兴她',''),
('Hos','zh','何西阿（一1）','','','','耶和華是邪淫背道之以色列的救恩，接納她回來並復興她',''),
('Joel','sc','约珥（一1）','','','','人类政权对以色列四个阶段的残害以及基督对残害者的毁坏，并祂在复兴时在以色列中间的掌权',''),
('Joel','zh','約珥（一1）','','','','人類政權對以色列四個階段的殘害以及基督對殘害者的毀壞，並祂在復興時在以色列中間的掌權',''),
('Amos','sc','阿摩司（一1下）','','','','耶和华对以色列并四围列国的审判以及所产生的复兴',''),
('Amos','zh','阿摩司（一1下）','','','','耶和華對以色列並四圍列國的審判以及所產生的復興',''),
('Obad','sc','俄巴底亚（1）','','','','耶和华对以扫的对付以及雅各为着耶和华国度的胜利',''),
('Obad','zh','俄巴底亞（1）','','','','耶和華對以掃的對付以及雅各為著耶和華國度的勝利',''),
('Jonah','sc','约拿（一1）','','','','耶和华的救恩甚至临到外邦人的城尼尼微',''),
('Jonah','zh','約拿（一1）','','','','耶和華的救恩甚至臨到外邦人的城尼尼微',''),
('Mic','sc','弥迦（一1）','','','','耶和华对以色列的责备，以及祂赐给以色列的复兴',''),
('Mic','zh','彌迦（一1）','','','','耶和華對以色列的責備，以及祂賜給以色列的復興',''),
('Nah','sc','那鸿（一1）','','','','耶和华对邪恶亚述之京城尼尼微的审判',''),
('Nah','zh','那鴻（一1）','','','','耶和華對邪惡亞述之京城尼尼微的審判',''),
('Hab','sc','哈巴谷（一1）','','','','神先借着迦勒底人对以色列施行公义的审判，然后又借着列国对迦勒底人施行公义的审判',''),
('Hab','zh','哈巴谷（一1）','','','','神先借著迦勒底人對以色列施行公義的審判，然後又藉著列國對迦勒底人施行公義的審判',''),
('Zeph','sc','西番雅（一1）','','','','耶和华对以色列和列国的审判，以及祂对外邦和以色列的拯救',''),
('Zeph','zh','西番雅（一1）','','','','耶和華對以色列和列國的審判，以及祂對外邦和以色列的拯救',''),
('Hag','sc','哈该（一1）','','','','耶和华对付被掳归回的人，以建造祂的殿',''),
('Hag','zh','哈該（一1）','','','','耶和華對付被擄歸回的人，以建造祂的殿',''),
('Zech','sc','撒迦利亚（一1）','','','','耶和华借着基督的救赎，对祂受管教的选民热切的安慰和应许；基督亲受屈辱，在他们被掳中作他们受苦的同伴',''),
('Zech','zh','撒迦利亞（一1）','','','','耶和華藉著基督的救贖，對祂受管教的選民熱切的安慰和應許；基督親受屈辱，在他們被擄中作他們受苦的同伴',''),
('Mal','sc','玛拉基（一1）','','','','耶和华对利未子孙（在以色列中间的祭司）和雅各子孙（以色列人）的对付',''),
('Mal','zh','瑪拉基（一1）','','','','耶和華對利未子孫（在以色列中間的祭司）和雅各子孫（以色列人）的對付',''),
('Mt','sc','马太，又名利未，原为税吏，后为使徒，（九9，路五27，）证以九10隐言设筵者，及十3特提税吏','约在主后三十七至四十年之间，证以在主复活后不久，（二八15，）圣殿被毁之前（二四2）','约在犹太地，只能如此推测，无法证定','','国度的福音─证明耶稣基督是君王救主','一般犹太人，证以本书不解释犹太人之习俗、节期等（十五2比可七2～3，二六17比可十四12）'),
('Mt','zh','馬太，又名利未，原為稅吏，後為使徒，（九9，路五27，）證以九10隱言設筵者，及十3特提稅吏','約在主後三十七至四十年之間，證以在主復活後不久，（二八15，）聖殿被毀之前（二四2）','約在猶太地，只能如此推測，無法證定','','國度的福音─證明耶穌基督是君王救主','一般猶太人，證以本書不解釋猶太人之習俗、節期等（十五2比可七2～3，二六17比可十四12）'),
('Mk','sc','马可，详见一1注1','本书十三2所言，可证此书写于圣殿被毁之前，或许在使徒保罗死后，主后六十七至七十年之间','或许在罗马城','','神的福音─证明耶稣基督是奴仆救主','本书多解释犹太的名称、习俗和节期，（三17，五41，七3，11，十四12，十五42，）证明本书乃写与外邦人，特别罗马人者'),
('Mk','zh','馬可，詳見一1注1','本書十三2所言，可證此書寫於聖殿被毀之前，或許在使徒保羅死後，主後六十七至七十年之間','或許在羅馬城','','神的福音─證明耶穌基督是奴僕救主','本書多解釋猶太的名稱、習俗和節期，（三17，五41，七3，11，十四12，十五42，）證明本書乃寫與外邦人，特別羅馬人者'),
('Lk','sc','路加，详见一3注1','约在主后六十年，在写使徒行传之前（徒一1）','无法推断，可能是在该撒利亚，当保罗在该地受监禁时（参徒二三33，二四27，二七1）','','赦罪的福音─证明耶稣基督是人救主','提阿非罗，（一1，）详见一1注1'),
('Lk','zh','路加，詳見一3注1','約在主後六十年，在寫使徒行傳之前（徒一1）','無法推斷，可能是在該撒利亞，當保羅在該地受監禁時（參徒二三33，二四27，二七1）','','赦罪的福音─證明耶穌基督是人救主','提阿非羅，（一1，）詳見一1注1'),
('Jn','sc','使徒约翰，（二一20，24，）为西庇太的儿子，（太十2，）他的哥哥是雅各，他的母亲是撒罗米（太二七56，可十五40）','约在主后九十年前后','或在以弗所','','生命的福音─证明耶稣基督是神救主，来作生命，使神得扩增','犹太外邦一切的信徒，证以一38，五2，十九13等处的解释'),
